import{_ as n,C as s,o,c as i,E as l,w as u,j as e,a as t}from"./chunks/framework.BueZayg5.js";const w=JSON.parse('{"title":"Are you teaching your students these core skills?","description":"","frontmatter":{"title":"Are you teaching your students these core skills?","author":"Signe Elisabeth Åsberg","date":"2026-03-03T00:00:00.000Z","category":"Article","intro":"There are countless skills you will pick up during your research career. Some are highly useful (like how to organize 300 references) while others are just weird (how to collect urin from mice).\\n\\nUnfortunately, there are key skills that seem to continuously slip beneath the radars of both supervisors and institutions. Here are the top 3 skills that I wish every every young researcher learnt and perfected throughout their careers:\\n","next":false,"prev":false},"headers":[],"relativePath":"articles/posts/2026-03-03-article-1.md","filePath":"articles/posts/2026-03-03-article-1.md"}'),c={name:"articles/posts/2026-03-03-article-1.md"};function h(d,r,g,m,p,y){const a=s("PostDetail");return o(),i("div",null,[l(a,null,{default:u(()=>[...r[0]||(r[0]=[e("p",null,"There are countless skills you will pick up during your research career. Some are highly useful (like how to organize 300 references) while others are just weird (how to collect urin from mice).",-1),e("p",null,"Unfortunately, there are key skills that seem to continuously slip beneath the radars of both supervisors and institutions. Here are the top 3 skills that I wish every every young researcher learnt and perfected throughout their careers:",-1),e("h4",{id:"writing",tabindex:"-1"},[t("Writing "),e("a",{class:"header-anchor",href:"#writing","aria-label":'Permalink to "Writing"'},"​")],-1),e("p",null,"Writing will make or break an academic career. You can’t produce papers or win grants if you’re not a great writer. In fact, I tell all my students that being a scientist, means being a writer.",-1),e("p",null,"Still, most universities provide few courses in academic writing. Hardly any have courses on how to build a sustainable writing practice.",-1),e("p",null,"As a supervisor, don’t rely on osmosis. Make sure your students become great writers.",-1),e("h4",{id:"economy-and-finances",tabindex:"-1"},[t("Economy and finances "),e("a",{class:"header-anchor",href:"#economy-and-finances","aria-label":'Permalink to "Economy and finances"'},"​")],-1),e("p",null,"Do NOT shield your students from the boring tasks of budgeting and managing the group’s finances. The more they understand of the academic financial mayhem, grant cycles, what person-months mean and who the project economist actually is - the better. Teaching them economy means you are setting them up for success! In turn, you get a research group that dosen’t think reagents grow on trees.",-1),e("h4",{id:"data-management-and-governance",tabindex:"-1"},[t("Data management and governance "),e("a",{class:"header-anchor",href:"#data-management-and-governance","aria-label":'Permalink to "Data management and governance"'},"​")],-1),e("p",null,"This key skill is often reduced to the mandatory DMP - which you click through in a hurry and never look at again. I see research groups struggling with this every day. Keeping a digital lab organized is surprisingly difficult. You don’t want to rely on one single post doc’s internalized map of the folders. Educate your PhDs in data management and governance, and it will make everyone’s lives easier.",-1),e("p",null,"What would you add to this list?",-1),e("p",null,"Links:",-1),e("ul",null,[e("li",null,[t("NTNU main channel: "),e("a",{href:"https://www.youtube.com/@NTNUUniversity",target:"_blank",rel:"noreferrer"},"@NTNUUniversity")]),e("li",null,[t("NTNU website: "),e("a",{href:"https://www.ntnu.no",target:"_blank",rel:"noreferrer"},"https://www.ntnu.no")]),e("li",null,[t("HUNT Research Centre: "),e("a",{href:"https://www.ntnu.edu/hunt",target:"_blank",rel:"noreferrer"},"https://www.ntnu.edu/hunt")]),e("li",null,[t("HUNT Cloud channel: "),e("a",{href:"https://www.youtube.com/@HUNTCloud",target:"_blank",rel:"noreferrer"},"@HUNTCloud")])],-1)])]),_:1})])}const k=n(c,[["render",h]]);export{w as __pageData,k as default};
